class Solution {
    public String minWindow(String s, String t) {
        if (s.isEmpty() || t.isEmpty() || s.length() < t.length()) {
            return "";
        }

        int[] map = new int[128];
        int count = t.length();
        int start = 0, end = 0;
        int minLen = Integer.MAX_VALUE;
        String minWindow = "";

        for (char c : t.toCharArray()) {
            map[c]++;
        }

        while (end < s.length()) {
            if (map[s.charAt(end)] > 0) {
                count--;
            }
            map[s.charAt(end)]--;
            end++;

            while (count == 0) {
                if (end - start < minLen) {
                    minLen = end - start;
                    minWindow = s.substring(start, end);
                }

                if (map[s.charAt(start)] == 0) {
                    count++;
                }
                map[s.charAt(start)]++;
                start++;
            }
        }

        return minWindow;
    }
}
